class TestClaudeSessions:
    def test_returns_raw_rows(self, client, db) -> None:
        run_async(
            schema.upsert_session(
                db,
                session_id="s1",
                pid=1234,
                cwd="/tmp",
                last_event="PreToolUse",
            )
        )
        resp = client.get("/api/v1/claude/sessions")
        assert resp.status_code == 200
        data = resp.json()
        assert len(data) == 1
        assert data[0]["session_id"] == "s1"
        assert "derived_state" not in data[0]


